'use client'

import { useState, useEffect, useRef } from 'react'
import ReactMarkdown from 'react-markdown'
import { 
  Send, 
  Plus, 
  FileText, 
  Trash2, 
  Upload,
  AlertCircle,
  Loader2,
  ChevronRight,
  User,
  Bot
} from 'lucide-react'
import { clsx, type ClassValue } from 'clsx'
import { twMerge } from 'tailwind-merge'
import styles from './page.module.css'

// Helper for conditional classes
function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs))
}

const API_BASE_URL = 'http://127.0.0.1:8000'

interface Message {
  role: 'user' | 'assistant'
  content: string
  sources?: any[]
}

interface Document {
  id: string
  filename: string
  status: string
  error?: string
}

export default function Home() {
  const [messages, setMessages] = useState<Message[]>([])
  const [inputText, setInputText] = useState('')
  const [documents, setDocuments] = useState<Document[]>([])
  const [isLoading, setIsLoading] = useState(false)
  const [isUploading, setIsUploading] = useState(false)
  const [selectedDocId, setSelectedDocId] = useState<string | null>(null)
  const [apiError, setApiError] = useState<string | null>(null)
  
  const fileInputRef = useRef<HTMLInputElement>(null)
  const scrollRef = useRef<HTMLDivElement>(null)
  const textareaRef = useRef<HTMLTextAreaElement>(null)

  // Fetch documents on mount
  useEffect(() => {
    fetchDocuments()
  }, [])

  // Scroll to bottom when messages change
  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight
    }
  }, [messages, isLoading])

  // Auto-resize textarea
  useEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto'
      textareaRef.current.style.height = `${textareaRef.current.scrollHeight}px`
    }
  }, [inputText])

  const fetchDocuments = async () => {
    try {
      const res = await fetch(`${API_BASE_URL}/api/documents`)
      if (res.ok) {
        const data = await res.json()
        setDocuments(data)
        setApiError(null)
      } else {
        setApiError(`Server error: ${res.status}`)
      }
    } catch (err) {
      console.error('Failed to fetch documents:', err)
      setApiError('Cannot connect to backend server. Make sure it is running on port 8000.')
    }
  }

  const handleSendMessage = async () => {
    if (!inputText.trim() || isLoading) return

    const userMessage: Message = { role: 'user', content: inputText }
    setMessages(prev => [...prev, userMessage])
    setInputText('')
    setIsLoading(true)

    try {
      const res = await fetch(`${API_BASE_URL}/api/query`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ query: inputText }),
      })

      if (res.ok) {
        const data = await res.json()
        setMessages(prev => [...prev, { 
          role: 'assistant', 
          content: data.answer,
          sources: data.sources 
        }])
      } else {
        const errorData = await res.json()
        setMessages(prev => [...prev, { 
          role: 'assistant', 
          content: `Error: ${errorData.detail || 'Something went wrong.'}` 
        }])
      }
    } catch (err) {
      setMessages(prev => [...prev, { 
        role: 'assistant', 
        content: 'Failed to connect to the backend. Please ensure the server is running on port 8000.' 
      }])
    } finally {
      setIsLoading(false)
    }
  }

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0]
    if (!file) return

    setIsUploading(true)
    const formData = new FormData()
    formData.append('file', file)

    try {
      const res = await fetch(`${API_BASE_URL}/api/upload`, {
        method: 'POST',
        body: formData,
      })
      if (res.ok) {
        const data = await res.json()
        const docId = data.id
        await fetchDocuments()
        
        // Poll for status update until it's active or failed
        const pollInterval = setInterval(async () => {
          try {
            const statusRes = await fetch(`${API_BASE_URL}/api/documents/${docId}`)
            if (statusRes.ok) {
              const statusData = await statusRes.json()
              if (statusData.status === 'active' || statusData.status === 'failed') {
                clearInterval(pollInterval)
                setIsUploading(false)
                fetchDocuments()
              }
            } else {
              clearInterval(pollInterval)
              setIsUploading(false)
            }
          } catch (err) {
            clearInterval(pollInterval)
            setIsUploading(false)
          }
        }, 3000)
      } else {
        const errorData = await res.json()
        alert(`Upload failed: ${errorData.detail}`)
        setIsUploading(false)
      }
    } catch (err) {
      alert('Failed to upload file.')
      setIsUploading(false)
    } finally {
      if (fileInputRef.current) fileInputRef.current.value = ''
    }
  }

  const handleDeleteDocument = async (id: string, e: React.MouseEvent) => {
    e.stopPropagation()
    if (!confirm('Are you sure you want to delete this document?')) return

    try {
      const res = await fetch(`${API_BASE_URL}/api/documents/${id}`, {
        method: 'DELETE',
      })
      if (res.ok) {
        setDocuments(prev => prev.filter(d => d.id !== id))
        if (selectedDocId === id) setSelectedDocId(null)
      }
    } catch (err) {
      alert('Failed to delete document.')
    }
  }

  return (
    <div className={styles.container}>
      {/* Sidebar */}
      <aside className={styles.sidebar}>
        <div className={styles.sidebarTitle}>Contract Repository</div>
        <div className={styles.documentList}>
          {documents.map(doc => (
            <div 
              key={doc.id} 
              className={cn(styles.documentItem, selectedDocId === doc.id && styles.documentItemActive)}
              onClick={() => setSelectedDocId(doc.id)}
            >
              <div className={styles.docName} title={`${doc.filename}${doc.error ? ` - Error: ${doc.error}` : ''}`}>
                <FileText size={14} style={{ marginRight: '8px', verticalAlign: 'middle', display: 'inline' }} />
                {doc.filename}
                {doc.status !== 'active' && (
                  <span style={{ fontSize: '0.7rem', marginLeft: '8px', color: doc.status === 'failed' ? '#ef4444' : '#f59e0b', textTransform: 'uppercase' }}>
                    ({doc.status})
                  </span>
                )}
              </div>
              <button 
                className={styles.deleteBtn}
                onClick={(e) => handleDeleteDocument(doc.id, e)}
              >
                <Trash2 size={14} />
              </button>
            </div>
          ))}
          {documents.length === 0 && !isUploading && (
            <div style={{ fontSize: '0.8rem', color: '#a1a19f', padding: '0 0.5rem', fontStyle: 'italic' }}>
              No contracts found.
            </div>
          )}
          {isUploading && (
            <div className={styles.documentItem} style={{ color: '#a1a19f' }}>
              <Loader2 size={14} className={styles['animate-spin']} style={{ marginRight: '8px' }} />
              Uploading...
            </div>
          )}
        </div>
        
        <button 
          className={styles.uploadButton}
          onClick={() => fileInputRef.current?.click()}
          disabled={isUploading}
        >
          {isUploading ? <Loader2 size={16} className={styles['animate-spin']} /> : <Plus size={16} />}
          {isUploading ? 'Ingesting...' : 'Add Contract'}
        </button>
        <input 
          type="file" 
          ref={fileInputRef} 
          onChange={handleFileUpload} 
          className={styles.hiddenInput} 
          accept=".pdf,.xlsx,.xls"
        />
      </aside>

      {/* Main Content */}
      <main className={styles.main}>
        <header className={styles.header}>
          <div className={styles.headerTitle}>
            Claude-Style Contract RAG
          </div>
        </header>

        {apiError && (
          <div style={{ 
            backgroundColor: '#fff1f0', 
            borderBottom: '1px solid #ffa39e', 
            padding: '8px 24px', 
            color: '#cf1322', 
            fontSize: '0.85rem',
            display: 'flex',
            alignItems: 'center',
            gap: '8px'
          }}>
            <AlertCircle size={14} />
            {apiError}
          </div>
        )}

        <div className={styles.chatContent} ref={scrollRef}>
          {messages.length === 0 ? (
            <div className={styles.emptyState}>
              <div style={{ maxWidth: '400px' }}>
                <div style={{ 
                  width: '64px', 
                  height: '64px', 
                  backgroundColor: '#f7f7f5', 
                  borderRadius: '16px', 
                  display: 'flex', 
                  alignItems: 'center', 
                  justifyContent: 'center',
                  margin: '0 auto 1.5rem auto',
                  border: '1px solid #e5e5e0'
                }}>
                  <Bot size={32} style={{ color: '#37352f' }} />
                </div>
                <h2 style={{ fontSize: '1.5rem', fontWeight: 600, color: '#1a1a1a', marginBottom: '0.75rem' }}>
                  Intelligent Contract Analysis
                </h2>
                <p style={{ color: '#6b6b6b', lineHeight: 1.6 }}>
                  Upload your mortgage purchase agreements or policy documents. I'll help you extract terms, obligations, and risks with high precision.
                </p>
                <div style={{ marginTop: '2rem', display: 'flex', flexDirection: 'column', gap: '0.75rem' }}>
                   <div style={{ fontSize: '0.85rem', color: '#8a8a86', textAlign: 'left', backgroundColor: '#f9f9f8', padding: '0.75rem', borderRadius: '8px', border: '1px solid #f0f0ee' }}>
                      Try: "What are the key obligations for the Seller?"
                   </div>
                   <div style={{ fontSize: '0.85rem', color: '#8a8a86', textAlign: 'left', backgroundColor: '#f9f9f8', padding: '0.75rem', borderRadius: '8px', border: '1px solid #f0f0ee' }}>
                      Try: "Summarize the risk levels in this contract."
                   </div>
                </div>
              </div>
            </div>
          ) : (
            <div className={styles.messageContainer}>
              {messages.map((msg, i) => (
                <div key={i} className={styles.message}>
                  <div className={cn(styles.avatar, msg.role === 'user' ? styles.userAvatar : styles.assistantAvatar)}>
                    {msg.role === 'user' ? <User size={16} /> : <Bot size={16} />}
                  </div>
                  <div className={styles.messageContent}>
                    <ReactMarkdown>{msg.content}</ReactMarkdown>
                    
                    {msg.sources && msg.sources.length > 0 && (
                      <div className={styles.sources}>
                        <div className={styles.sourcesTitle}>Reference Sources</div>
                        <div className={styles.sourceGrid}>
                          {msg.sources.map((source, si) => (
                            <div key={si} className={styles.sourceCard}>
                              <div style={{ fontWeight: 600, marginBottom: '4px', fontSize: '0.75rem', color: '#1a1a1a' }}>
                                SECTION {source.section || '?'}
                              </div>
                              <div style={{ fontSize: '0.7rem', color: '#6b6b6b', overflow: 'hidden', textOverflow: 'ellipsis', display: '-webkit-box', WebkitLineClamp: 3, WebkitBoxDirection: 'vertical', lineHeight: 1.4 }}>
                                {source.snippet}
                              </div>
                              {source.feat_risk_level && (
                                <div style={{ marginTop: '6px', fontSize: '0.65rem', fontWeight: 600, color: source.feat_risk_level === 'High' ? '#ef4444' : '#f59e0b' }}>
                                  Risk: {source.feat_risk_level}
                                </div>
                              )}
                            </div>
                          ))}
                        </div>
                      </div>
                    )}
                  </div>
                </div>
              ))}
              {isLoading && (
                <div className={styles.message}>
                  <div className={cn(styles.avatar, styles.assistantAvatar)}>
                    <Bot size={16} />
                  </div>
                  <div className={styles.messageContent}>
                    <div className={styles.loader}>
                      <div className={styles.dot}></div>
                      <div className={styles.dot}></div>
                      <div className={styles.dot}></div>
                    </div>
                  </div>
                </div>
              )}
            </div>
          )}
        </div>

        <div className={styles.inputArea}>
          <div className={styles.inputWrapper}>
            <textarea
              ref={textareaRef}
              className={styles.textarea}
              placeholder="Ask anything about the contracts..."
              value={inputText}
              onChange={(e) => setInputText(e.target.value)}
              onKeyDown={(e) => {
                if (e.key === 'Enter' && !e.shiftKey) {
                  e.preventDefault()
                  handleSendMessage()
                }
              }}
              rows={1}
            />
            <button 
              className={styles.sendButton}
              onClick={handleSendMessage}
              disabled={!inputText.trim() || isLoading}
            >
              {isLoading ? <Loader2 size={18} className={styles['animate-spin']} /> : <Send size={18} />}
            </button>
          </div>
          <div style={{ fontSize: '0.7rem', color: '#a1a19f', textAlign: 'center', marginTop: '0.75rem' }}>
            Built with RAG technology. Please verify critical information.
          </div>
        </div>
      </main>
    </div>
  )
}
